1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	};
9	
10	type Item = { type: string };
11	type QuoteStep = { op: "quote"; items: Item[] };
12	type Step = QuoteStep;
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	
15	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
16	
17	const quotePremium = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + basePremiumFor(item), 0) + PROCESSING_FEE;
19	
20	export const processScenario = (scenario: Scenario): unknown => {
21	  const results = scenario.steps.map((step) => ({
22	    premium: quotePremium(step.items),
23	  }));
24	  return { results };
25	};
